// // This module is designed to capture an input signal 'd' on the falling edge of a clock signal 'clk' and shift the previously stored data through its three flip-flops. The output 'q' reflects the least significant bit of the current stored value in the register. When the clock ticks, 'd' enters the most significant position, while the other bits are shifted to the left.
module top_module(input clk, input d, output q);reg [2:0] reg_data;
  reg [2:0] next_data;

  always @(posedge clk) begin
    next_data[0] = d;
    next_data[1] = reg_data[0];
    next_data[2] = reg_data[1];
    reg_data <= next_data;
  end

  assign q = reg_data[2];
endmodule
